// OrderList.js
import React, { useState,useCallback, useEffect } from 'react';

const OrderList = ({ apiBaseUrl }) => {
  const [orders, setOrders] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchAPI = useCallback(async (url, options = {}) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        'Authorization': `Bearer ${authToken}`,
        'Content-Type': 'application/json',
      },
    });
    if (!response.ok) {
      const errorResponse = await response.json();
      throw new Error(errorResponse.message || `Error fetching ${url}`);
    }
    return response.json();
  }, []);




  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetchAPI(`${apiBaseUrl}/order_listAPI`);
    
        setOrders(response);
      } catch (error) {
        setError(error.message);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, [apiBaseUrl, fetchAPI]);

  console.log(orders);

  const columns = React.useMemo(
    () => [
      { Header: 'Material ID', accessor: 'matid' },
      { Header: 'Name', accessor: 'name' },
      { Header: 'Description', accessor: 'description' },
      { Header: 'Field', accessor: 'field' },
      { Header: 'Unit of Measure', accessor: 'unit_of_measure' },
      { Header: 'Extra Characteristics', accessor: 'extras' },
      { Header: 'Shelf Life', accessor: 'shelflife' },
      { Header: 'Minimum Stock', accessor: 'minstock' },
      {
        Header: 'Actions',
        Cell: ({ row }) => (
          <div>
            <button >Edit</button>
            <button >Delete</button>
          </div>
        ),
      },
    ],
    []
  );

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize, globalFilter },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data: materials,
    },
    useGlobalFilter,
    useSortBy,
    usePagination
  );

  if (isLoading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;

  return (
    <div>
      <h2>Orders</h2>
      <table>
      <thead>
  <tr>
    <th>Order ID</th>
    <th>Location ID</th>
    <th>Material ID</th>
    <th>Vendor ID</th>
    <th>Quantity</th>
    <th>Comments</th>
    <th>Status</th>
    {/* Add more headers if there are more columns */}
  </tr>
</thead>
<tbody>
  {orders.map((order, index) => (
    <tr key={index}>
      <td>{order.order_list_id}</td>
      <td>{order.location_id}</td>
      <td>{order.material_id}</td>
      <td>{order.vendor_id}</td>
      <td>{order.quantity}</td>
      <td>{order.comments}</td>
      <td>{order.status}</td>
    </tr>
  ))}
</tbody>

      </table>
    </div>
  );
};

export default OrderList;
